        assert_true(idem_second["execution"]["ok"], "idempotent add second call should reuse success")
        assert_true(bool((idem_second.get("idempotency") or {}).get("reused", False)), "second idempotent call should be reused")
        session_after_idem = get_json(client, f"/api/session/{sid}")
        after_idem_tasks = list((session_after_idem.get("memory", {}) or {}).get("tasks", []))
        assert_true(len(after_idem_tasks) == len(before_idem_tasks) + 1, "idempotency retry should apply mutation only once")
        assert_true(int(idem_second.get("revision", 0) or 0) == int(idem_first.get("revision", 0) or 0), "reused idempotent response should preserve revision")
